import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"41A. Change Of Ward Allowance","description":"","frontmatter":{"title":"41A. Change Of Ward Allowance","eba":"Nurses and Midwives 2024-2028","topics":["allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.md","filePath":"ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.md"}'),n={name:"ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.md"};function s(i,e,l,d,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_41a-change-of-ward-allowance" tabindex="-1">41A. Change Of Ward Allowance <a class="header-anchor" href="#_41a-change-of-ward-allowance" aria-label="Permalink to &quot;41A. Change Of Ward Allowance&quot;">​</a></h1><p><strong>41A.1</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> Base Ward means the Ward or Unit to which the Employee was rostered to work in accordance with <a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a> (Rosters).</p><p><strong>(b)</strong> Multi Base Ward Employee means an Employee who is contracted to work on more than one Base Ward.</p><p><strong>41A.2</strong> Relocation from Base Ward – from 26 June 2024</p><p><strong>(a)</strong> The Employer will ensure that rosters are issued on a per ward or unit basis.</p><p><strong>(b)</strong> The allowance under this clause shall apply from 26 June 2024.</p><p><strong>(c)</strong> Where, at the initiative of the Employer, an Employee performs their rostered shift at a ward, unit or Department that is not their Base Ward, the Employee will be entitled to the Change of Ward Allowance.</p><p><strong>(d)</strong> The Change of Ward Allowance is set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2.</p><p><strong>41A.3</strong> Change of Ward Allowance - exceptions</p><p>The allowance in this clause does not apply to:</p><p><strong>(a)</strong> A casual Employee, including a Bank Employee;</p><p><strong>(b)</strong> A Pool Employee;</p><p><strong>(c)</strong> Subject to subclause 41A.6 below, an Employee whose role is genuinely not ward based, such as an After Hours Coordinator, Educators, Advanced Practice Nurse/Midwife or who does not ordinarily work in a ward;</p><p><strong>(d)</strong> An Employee not rostered to work in an aged care ward, undertaking ad hoc assessment or supervision duties in an aged care ward for part of a shift;</p><p><strong>(e)</strong> An additional shift that a part-time Employee has agreed to work, unless relocated from the ward on which the additional shift was scheduled to take place;</p><p><strong>(f)</strong> A post-registration student who is required to operate in another ward, unit or department due to their academic requirements;</p><p><strong>(g)</strong> A Nurse/Midwife who is required to follow their patient to other units/wards e.g. Diagnostic Imaging and Operating Theatre;</p><p><strong>(h)</strong> Working from home arrangements or other like arrangements;</p><p><strong>(i)</strong> Community Health Centres; or</p><p><strong>(j)</strong> A Multi Base Ward Employee to the extent they are working on a Base Ward in accordance with their roster.</p><p>Example: An Employee is contracted to work on Ward A on some days, and Ward B on other days. Ward A and Ward B are Base Wards for the purposes of this clause. A Multi Base Ward Employee who, at the initiative of the Employer, performs their rostered shift at a ward, unit or department that is not their Base Ward, will be entitled to the Change of Ward Allowance.</p><p><strong>41A.4</strong> Anti-avoidance</p><p>Employers must not seek to circumvent this provision by, for example, defining multiple wards as one ward, declaring Employees to be part of a pool arrangement or Multi Base Ward Employee contrary to their wishes, amalgamating cost centres, or not rostering to a ward, unit, clinical section or department where that would ordinarily be the case.</p><p><strong>41A.5</strong> Additional Provisions</p><p>Additional provisions apply where an Employee redeploys to a Campus that is not their Base Employment Campus, (see <a href="/eba/ebas/nurses-midwives/allowances/37-travelling-and-relocation.html">clause 37</a>), or the redeployment is as a result of the Employee being an Affected Employee (see <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clauses 11</a> and/or 12).</p><p><strong>41A.6</strong> An Employee will also be eligible for the Change of Ward allowance in the following circumstances in a manner consistent with the principles at 41A.2, 41A.3 and 41A.4 above:</p><p><strong>(a)</strong> if not ordinarily ward based, but is relocated/redeployed into a ward to provide direct patient care; or</p><p><strong>(b)</strong> where a Base Ward has more than one readily identifiable clinical section, and the Employee is rostered to work in one clinical section of a ward/unit who is allocated into another clinical section of a ward/unit. Clinical sections for the purposes of this subclause 41A.6(b) include birth suite, special care nursery and post-natal, in some Maternity Wards or recovery and operating theatres in a surgical suite.</p><p>Example for subclause 41A.6(b):</p><p>Susan is a midwife on a maternity ward that includes post-natal, birth suite and special care nursery. On Tuesday Susan is rostered to work in birth suite, but is reallocated to post-natal. The Change of Ward allowance applies.</p><p><strong>(c)</strong> The application of this subclause consistent with 41A.2, 41A.3 and 41A.4 will be overseen by the WIC and, without limiting any right under <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a>, unresolved disputes will be escalated to the Central Implementation Committee and, if unresolved to the Statewide Industry Panel under <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a>.</p>',33)])])}const w=a(n,[["render",s]]);export{u as __pageData,w as default};
